# @cctt_verify {"v":2,"sym":"sympy.solvers.diophantine.tests.test_diophantine.test_descent","kind":"function","src_hash":"67000b74cfa86a18","in":{"base":"Any"},"out":{"base":"Any","pred":"a * x ** 2 + b * y ** 2 == w ** 2"},"spec":{"lhs":"test_descent()","rhs":"test_descent produces the expected output","over":{"base":"Any"},"name":"test_descent_correct"},"guarantee":"test_descent produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.solvers.diophantine.tests.test_diophantine.test_descent_correct","statement":"Path(test_descent(x), test_descent produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"a3f9c71f29fad859"}
def test_descent():

    u = ([(13, 23), (3, -11), (41, -113), (91, -3), (1, 1), (1, -1), (17, 13), (123689, 1), (19, -570)])
    for a, b in u:
        w, x, y = descent(a, b)
        assert a*x**2 + b*y**2 == w**2
    # the docstring warns against bad input, so these are expected results
    # - can't both be negative
    raises(TypeError, lambda: descent(-1, -3))
    # A can't be zero unless B != 1
    raises(ZeroDivisionError, lambda: descent(0, 3))
    # supposed to be square-free
    raises(TypeError, lambda: descent(4, 3))


