# @cctt_verify {"v":2,"sym":"sympy.solvers.diophantine.tests.test_diophantine.test_assumptions","kind":"function","src_hash":"aa57a05947a63f73","in":{"base":"Any"},"out":{"base":"Any","pred":"diof == {(5, 20), (40, 10), (95, 5), (121, 4), (248, 2), (499, 1)} and diof == {(-15, -3), (-9, -4), (-7, -5), (-6, -6), (-5, -8), (-4, -14)} and diof == {(1, -5), (-3, 5), (0, 0)} and diof == set() and diof == {(0, 0)}"},"spec":{"lhs":"test_assumptions()","rhs":"test whether diophantine respects the assumptions","over":{"base":"Any"},"name":"test_assumptions_correct"},"guarantee":"test whether diophantine respects the assumptions","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.solvers.diophantine.tests.test_diophantine.test_assumptions_correct","statement":"Path(test_assumptions(x), test whether diophantine respects the assumptions)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"b97848e628dc84e9"}
def test_assumptions():
    """
    Test whether diophantine respects the assumptions.
    """
    #Test case taken from the below so question regarding assumptions in diophantine module
    #https://stackoverflow.com/questions/23301941/how-can-i-declare-natural-symbols-with-sympy
    m, n = symbols('m n', integer=True, positive=True)
    diof = diophantine(n**2 + m*n - 500)
    assert diof == {(5, 20), (40, 10), (95, 5), (121, 4), (248, 2), (499, 1)}

    a, b = symbols('a b', integer=True, positive=False)
    diof = diophantine(a*b + 2*a + 3*b - 6)
    assert diof == {(-15, -3), (-9, -4), (-7, -5), (-6, -6), (-5, -8), (-4, -14)}

    x, y = symbols('x y', integer=True)
    diof = diophantine(10*x**2 + 5*x*y - 3*y)
    assert diof == {(1, -5), (-3, 5), (0, 0)}

    x, y = symbols('x y', integer=True, positive=True)
    diof = diophantine(10*x**2 + 5*x*y - 3*y)
    assert diof == set()

    x, y = symbols('x y', integer=True, negative=False)
    diof = diophantine(10*x**2 + 5*x*y - 3*y)
    assert diof == {(0, 0)}


