# @cctt_verify {"v":2,"sym":"sympy.solvers.diophantine.tests.test_diophantine.check_solutions","kind":"function","src_hash":"c444b36123bf8d76","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"check_solutions(eq)","rhs":"determines whether solutions returned by diophantine() satisfy the original equation","over":{"base":"Any"},"name":"check_solutions_correct"},"guarantee":"determines whether solutions returned by diophantine() satisfy the original equation","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.solvers.diophantine.tests.test_diophantine.check_solutions_correct","statement":"Path(check_solutions(x), determines whether solutions returned by diophantine() satisfy the original equation)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"753212fb3edc2ccd"}
def check_solutions(eq):
    """
    Determines whether solutions returned by diophantine() satisfy the original
    equation. Hope to generalize this so we can remove functions like check_ternay_quadratic,
    check_solutions_normal, check_solutions()
    """
    s = diophantine(eq)

    factors = Mul.make_args(eq)

    var = list(eq.free_symbols)
    var.sort(key=default_sort_key)

    while s:
        solution = s.pop()
        for f in factors:
            if diop_simplify(f.subs(zip(var, solution))) == 0:
                break
        else:
            return False
    return True


